class Solution(object):
    def longestSubarray(self, nums):
        n = len(nums)
        # pref[i] = longest non-decreasing subarray ending at i
        # suff[i] = longest non-decreasing subarray starting at i
        pref = [1] * n
        for i in range(1, n):
            if nums[i] >= nums[i-1]:
                pref[i] = pref[i-1] + 1

        suff = [1] * n
        for i in range(n-2, -1, -1):
            if nums[i] <= nums[i+1]:
                suff[i] = suff[i+1] + 1

        ans = max(max(pref), max(suff))
        # Replace element at position i: connect pref[i-1] and suff[i+1]
        for i in range(n):
            total = 1
            if i > 0:
                total += pref[i-1]
            if i < n-1:
                total += suff[i+1]
            # But need to check compatibility:
            # pref[i-1] ending at nums[i-1], suff[i+1] starting at nums[i+1]
            # We replace nums[i] with something in [nums[i-1], nums[i+1]].
            # Only valid if nums[i-1] <= nums[i+1] (we can bridge them)
            if i > 0 and i < n-1:
                if nums[i-1] <= nums[i+1]:
                    ans = max(ans, pref[i-1] + 1 + suff[i+1])
                else:
                    ans = max(ans, max(pref[i-1] + 1, 1 + suff[i+1]))
            elif i == 0 and i < n-1:
                ans = max(ans, 1 + suff[i+1])
            elif i > 0 and i == n-1:
                ans = max(ans, pref[i-1] + 1)
        return ans
